parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "response": {
      "type": "string",
      "description": "Mensaje natural al usuario."
    },
    "parameters": {
      "type": "object",
      "properties": {
        "tipo_agendamiento": {
          "type": ["string", "null"],
          "enum": ["cita", "llamada", null],
          "description": "Tipo de reunión a agendar. Null si aún no ha sido definido por el usuario."
        },
        "fecha_hora": {
          "type": ["string", "null"],
          "pattern": "^\\d{4}-(?:0[1-9]|1[0-2])-(?:0[1-9]|[12]\\d|3[01])T(?:[01]\\d|2[0-3]):[0-5]\\d$",
          "description": "Formato ISO YYYY-MM-DDTHH:MM"
        },
        "numero_habitaciones": {
          "type": ["string", "null"],
          "pattern": "^[1-9]\\d*$",
          "description": "Solo requerido si es 'cita'. Null si es 'llamada'."
        },
        "intencion_compra": {
          "type": ["string", "null"],
          "enum": [null, "V", "I"],
          "description": "V = Vivir, I = Invertir"
        },
        "metodo_contacto_pref": {
          "type": ["string", "null"],
          "enum": [null, "2", "3", "4", "5"],
          "description": "2=Correo, 3=Llamada, 4=WhatsApp, 5=Cualquiera"
        },
        "estado_civil": {
          "type": ["string", "null"],
          "enum": [null, "soltero", "casado", "divorciado", "viudo", "union_libre"],
          "description": "Estado civil del prospecto. Null si no lo proporciona."
        }
      },
      "required": [
        "tipo_agendamiento",
        "fecha_hora",
        "metodo_contacto_pref"
      ],
      "additionalProperties": false
    }
  },
  "required": ["response", "parameters"]
}

