function prepareForHttp(text) {
  if (text === null || text === undefined) return "";

  return String(text)
    .replace(/\\/g, "\\\\")      // Escapar barras invertidas primero
    .replace(/"/g, '\\"')        // Escapar comillas dobles
    .replace(/\r\n/g, "\\n")     // Primero \r\n (Windows)
    .replace(/\n/g, "\\n")       // Luego \n (Unix/macOS)
    .replace(/\t/g, "\\t")       // Tabulaciones
    .replace(/\*\*/g, "*")       // Eliminar doble asterisco
    .trim();
}

const text = $('RESPONSE AGENT').first().json.output;

const modified_text = prepareForHttp(text);

return {modified_text};

