// Capturamos la salida del agente
const rawOutput = $input.first().json.output || $input.first().json.text || "";

try {
  // 1. Extraemos solo el bloque JSON
  const inicio = rawOutput.indexOf('{');
  const fin = rawOutput.lastIndexOf('}') + 1;

  if (inicio === -1 || fin === 0) throw new Error("No se encontró un JSON válido");

  let jsonString = rawOutput.substring(inicio, fin);

  // 2. Limpieza de saltos de línea que rompen el parseo
  let jsonLimpio = jsonString.replace(/[\n\r]/g, " ");

  // 3. Convertimos a objeto real
  const objeto = JSON.parse(jsonLimpio);

  // 4. Retornamos TODOS los campos, incluyendo la bandera de transferencia
  return {
    nombre: objeto.nombre,
    telefono: objeto.telefono,
    correo: objeto.correo,
    // Agregamos la variable que faltaba
    transferir_agente: objeto.transferir_agente !== undefined ? objeto.transferir_agente : 0, 
    response: objeto.response || ""
  };

} catch (error) {
  // Manejo de errores para no romper el workflow
  return {
    nombre: null,
    telefono: null,
    correo: null,
    transferir_agente: 1, // Por seguridad, si falla el JSON, podrías querer que un humano revise
    response: rawOutput,
    debug_error: error.message
  };
}

